// // This is a 16-bit bidirectional shift register with parallel load, enable, shift direction, and asynchronous reset.
// (1) enable: Disables the register. Active low.
// (2) load: Unloads a specific value from the register. Active low.
// (3) dir: Direction of shift. 0 for right, 1 for left.
// (4) reset: Synchronous reset of the register. Active low.
// (5) clk: Clock signal.
// (6) load_value: 16-bit value to unload from the register.
// (7) q: 16-bit output of the register.
module top_module(
	input clk,
	input enable,
	input load,
	input dir,
	input reset,
	input [15:0] load_value,
	output reg [15:0] q);always @(posedge clk or posedge reset) begin
	if (reset)
		q <= 16'b0;
	else if (load)
		q <= load_value;
	else if (enable) begin
		if (dir)
			q <= {1'b0, q[15:1]};
		else
			q <= {q[14:0], 1'b0};
	end
end
endmodule

